import styled from 'styled-components'

export const CardContainer = styled.div`
    border: solid black 3px;
    width: 20vw;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-contente: center;
    padding: 1vh;
    background-color: lightgray;
    margin: 2vw;

    img {
        width: 15vw;
        height: 40vh;

    }

    button {
        width: 100%;
    }
`
